using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class TicketBookingService
{
    private readonly EventContext _context;

    public TicketBookingService(EventContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity, string userId)
    {
        if (quantity <= 0)
            throw new ArgumentException("Quantity must be greater than zero", nameof(quantity));

        if (string.IsNullOrEmpty(userId))
            throw new ArgumentException("User ID cannot be null or empty", nameof(userId));

        var ticket = await _context.Tickets
            .Where(t => t.EventId == eventId)
            .FirstOrDefaultAsync();

        if (ticket == null)
            return false;

        if (ticket.AvailableSeats < quantity)
            return false;

        using var transaction = await _context.Database.BeginTransactionAsync();

        try
        {
            var updatedRows = await _context.Tickets
                .Where(t => t.EventId == eventId && t.AvailableSeats >= quantity)
                .ExecuteUpdateAsync(setters => setters
                    .SetProperty(t => t.AvailableSeats, t => t.AvailableSeats - quantity)
                    .SetProperty(t => t.UpdatedAt, DateTime.UtcNow));

            if (updatedRows == 0)
            {
                await transaction.RollbackAsync();
                return false;
            }

            var purchase = new Purchase
            {
                EventId = eventId,
                UserId = userId,
                Quantity = quantity,
                PurchaseDate = DateTime.UtcNow,
                TotalAmount = quantity * ticket.Price
            };

            await _context.Purchases.AddAsync(purchase);
            await _context.SaveChangesAsync();
            await transaction.CommitAsync();

            return true;
        }
        catch
        {
            await transaction.RollbackAsync();
            throw;
        }
    }
}

public class EventContext : DbContext
{
    public EventContext(DbContextOptions<EventContext> options) : base(options) { }

    public DbSet<Ticket> Tickets { get; set; }
    public DbSet<Purchase> Purchases { get; set; }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Ticket>(entity =>
        {
            entity.HasKey(t => t.EventId);
            entity.Property(t => t.EventId).ValueGeneratedNever();
            entity.Property(t => t.Price).HasColumnType("decimal(18,2)");
            entity.Property(t => t.AvailableSeats).IsRequired();
        });

        modelBuilder.Entity<Purchase>(entity =>
        {
            entity.HasKey(p => p.Id);
            entity.Property(p => p.TotalAmount).HasColumnType("decimal(18,2)");
            entity.Property(p => p.PurchaseDate).IsRequired();
        });
    }
}

public class Ticket
{
    public int EventId { get; set; }
    public decimal Price { get; set; }
    public int AvailableSeats { get; set; }
    public DateTime UpdatedAt { get; set; }
}

public class Purchase
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public string UserId { get; set; }
